from collections import Counter

def get_Odd_Occurrence(arr):
    counts = Counter(arr)
    for key, value in counts.items():
        if value % 2 == 1:
            return key

# Test cases
assert get_Odd_Occurrence([1,2,3,1,2,3,1]) == 1
assert get_Odd_Occurrence([1,2,3,2,3,1,3]) == 3
assert get_Odd_Occurrence([2,3,5,4,5,2,4,3,5,2,4,4,2]) == 5

